function _seedIfEmpty() {
  if (localStorage.getItem(DB_PREFIX + 'seeded_v2')) return;

  // Usuários
  const users = [{
    id: _uuid(),
    email: 'admin@bovgest.com',
    password: 'admin123',
    user_metadata: { full_name: 'Administrador', role: 'admin', farm_name: 'Fazenda BovGest' },
    created_at: _now(),
  }];
  localStorage.setItem(DB_PREFIX + 'users', JSON.stringify(users));

  // Operações de Compra e Venda
  const ops = PLANILHA_DATA.operacoes.map((o, i) => ({ ...o, id: 'op_' + i }));
  _dbSet('operacoes', ops);

  // Contas a Pagar
  const cp = PLANILHA_DATA.contas_pagar.map((o, i) => ({ ...o, id: 'cp_' + i }));
  _dbSet('contas_pagar', cp);

  // Contas a Receber
  const cr = PLANILHA_DATA.contas_receber.map((o, i) => ({ ...o, id: 'cr_' + i }));
  _dbSet('contas_receber', cr);

  // Movimentações
  const mv = PLANILHA_DATA.movimentacoes.map((o, i) => ({ ...o, id: 'mv_' + i }));
  _dbSet('movimentacoes', mv);

  // Despesas
  const dp = PLANILHA_DATA.despesas.map((o, i) => ({ ...o, id: 'dp_' + i }));
  _dbSet('despesas', dp);

  // Geral mensal
  _dbSet('geral', PLANILHA_DATA.geral);

  // Lançamentos bancários
  _dbSet('lancamentos_conta', PLANILHA_DATA.lancamentos_conta);
  _dbSet('lancamentos_cofre', PLANILHA_DATA.lancamentos_cofre);

  localStorage.setItem(DB_PREFIX + 'seeded_v2', '1');
}

_seedIfEmpty();

// ─── AUTH ─────────────────────────────────────────────────────────────────────
async function signIn(email, password) {
  const users = JSON.parse(localStorage.getItem(DB_PREFIX + 'users') || '[]');
  const user  = users.find(u => u.email === email && u.password === password);
  if (!user) throw new Error('E-mail ou senha incorretos.');
  const session = {
    access_token: 'local_' + _uuid(),
    user: { id: user.id, email: user.email, user_metadata: user.user_metadata },
    expires_at: Math.floor(Date.now() / 1000) + 86400 * 30,
  };
  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
  return session;
}
async function signOut() { localStorage.removeItem(SESSION_KEY); }
function getCurrentUser() {
  try { return JSON.parse(localStorage.getItem(SESSION_KEY) || 'null')?.user || null; }
  catch { return null; }
}
function isAuthenticated() {
  const user = getCurrentUser();
  if (!user) return false;
  try {
    const s = JSON.parse(localStorage.getItem(SESSION_KEY));
    if (s?.expires_at && Date.now()/1000 > s.expires_at) { localStorage.removeItem(SESSION_KEY); return false; }
  } catch {}
  return true;
}

// ─── OPERAÇÕES (Compras e Vendas) ─────────────────────────────────────────────
async function getOperacoes(filters = {}) {
  let rows = _dbGet('operacoes');
  if (filters.mes)        rows = rows.filter(r => r.data_venda?.startsWith(filters.mes) || r.data_compra?.startsWith(filters.mes));
  if (filters.fornecedor) rows = rows.filter(r => r.fornecedor?.toLowerCase().includes(filters.fornecedor.toLowerCase()));
  if (filters.comprador)  rows = rows.filter(r => r.comprador?.toLowerCase().includes(filters.comprador.toLowerCase()));
  if (filters.referencia) rows = rows.filter(r => r.referencia?.toLowerCase().includes(filters.referencia.toLowerCase()));
  return rows;
}
async function insertOperacao(op) {
  const rows = _dbGet('operacoes');
  const n = { ...op, id: _uuid(), created_at: _now() };
  rows.unshift(n); _dbSet('operacoes', rows); return n;
}
async function updateOperacao(id, changes) {
  const rows = _dbGet('operacoes');
  const i = rows.findIndex(r => r.id === id);
  if (i < 0) throw new Error('Não encontrado.');
  rows[i] = { ...rows[i], ...changes }; _dbSet('operacoes', rows); return rows[i];
}
async function deleteOperacao(id) {
  _dbSet('operacoes', _dbGet('operacoes').filter(r => r.id !== id));
}

// ─── CONTAS A PAGAR ───────────────────────────────────────────────────────────
async function getContasPagar(filters = {}) {
  let rows = _dbGet('contas_pagar');
  if (filters.situacao) rows = rows.filter(r => r.situacao === filters.situacao.toUpperCase());
  if (filters.mes)      rows = rows.filter(r => r.ref?.startsWith(filters.mes));
  return rows.sort((a,b) => (a.data_pgto||'').localeCompare(b.data_pgto||''));
}
async function insertContaPagar(item) {
  const rows = _dbGet('contas_pagar');
  const n = { ...item, id: _uuid(), created_at: _now() };
  rows.unshift(n); _dbSet('contas_pagar', rows); return n;
}
async function updateContaPagar(id, changes) {
  const rows = _dbGet('contas_pagar');
  const i = rows.findIndex(r => r.id === id);
  if (i<0) throw new Error('Não encontrado.');
  rows[i] = {...rows[i],...changes}; _dbSet('contas_pagar', rows); return rows[i];
}
async function deleteContaPagar(id) {
  _dbSet('contas_pagar', _dbGet('contas_pagar').filter(r => r.id !== id));
}

