async function getMovimentacoes(filters = {}) {
  let rows = _dbGet('movimentacoes').sort((a,b) => b.data.localeCompare(a.data));
  if (filters.conta)         rows = rows.filter(r => r.conta?.includes(filters.conta));
  if (filters.identificacao) rows = rows.filter(r => r.identificacao === filters.identificacao);
  if (filters.mes)           rows = rows.filter(r => r.data?.startsWith(filters.mes));
  return rows;
}
