// ─── DESPESAS ────────────────────────────────────────────────────────────────
async function getDespesas(filters = {}) {
  let rows = _dbGet('despesas');
  if (filters.mes_num) rows = rows.filter(r => r.mes_num === filters.mes_num);
  if (filters.categoria) rows = rows.filter(r => r.categoria === filters.categoria);
  return rows;
}
async function upsertDespesa(item) {
  const rows = _dbGet('despesas');
  const i = rows.findIndex(r => r.categoria === item.categoria && r.mes_num === item.mes_num);
  if (i >= 0) { rows[i] = {...rows[i], ...item}; }
  else { rows.push({ ...item, id: _uuid() }); }
  _dbSet('despesas', rows);
}

