async function getLancamentosCofre() { return _dbGet('lancamentos_cofre'); }

// ─── DASHBOARD SUMMARY ───────────────────────────────────────────────────────
async function getDashboardSummary() {
  const geral  = _dbGet('geral').filter(r => r.compras || r.vendas);
  const cp     = _dbGet('contas_pagar');
  const cr     = _dbGet('contas_receber');
  const conta  = _dbGet('lancamentos_conta');
  const cofre  = _dbGet('lancamentos_cofre');

  const ultimoGeral = geral[geral.length - 1] || {};
  const totalCompras   = geral.reduce((s,r) => s + (r.compras||0), 0);
  const totalVendas    = geral.reduce((s,r) => s + (r.vendas||0), 0);
  const totalDespesas  = geral.reduce((s,r) => s + (r.despesas||0), 0);
  const totalLucro     = geral.reduce((s,r) => s + (r.lucro_liquido||0), 0);
  const qtGado         = ultimoGeral.qt_gado || 0;
  const valorGado      = ultimoGeral.valor_final_gado || 0;

  // Pendentes
  const aPagar     = cp.filter(r => r.situacao !== 'OK' || r.pago === 0);
  const aReceber   = cr.filter(r => r.situacao !== 'OK' || r.recebido === 0);
  const totalAPagar    = aPagar.reduce((s,r) => s + (r.valor||0), 0);
  const totalAReceber  = aReceber.reduce((s,r) => s + (r.valor||0), 0);

  // Saldos atuais
  const saldoConta = conta[conta.length-1]?.saldo_final || 0;
  const saldoCofre = cofre[cofre.length-1]?.saldo_final || 0;

  return {
    totalCompras, totalVendas, totalDespesas, totalLucro,
    qtGado, valorGado,
    totalAPagar, totalAReceber,
    saldoConta, saldoCofre,
    situacaoFinanceira: totalLucro + valorGado + saldoConta + saldoCofre - totalAPagar,
    geral,
  };
}

// ─── ADMIN ────────────────────────────────────────────────────────────────────
async function adminCreateUser({ email, password, full_name, role, farm_name, phone }) {
  const users = JSON.parse(localStorage.getItem(DB_PREFIX + 'users') || '[]');
  if (users.find(u => u.email === email)) throw new Error('E-mail já cadastrado.');
  const nu = { id: _uuid(), email, password, user_metadata: { full_name, role, farm_name, phone }, created_at: _now() };
  users.push(nu);
  localStorage.setItem(DB_PREFIX + 'users', JSON.stringify(users));
  return { user: nu };
}
async function getProfile(userId) {
  const id = userId || getCurrentUser()?.id;
  return _dbGet('profiles').find(r => r.id === id) || null;
}
async function updateProfile(changes) {
  const id = getCurrentUser()?.id;
  const rows = _dbGet('profiles');
  const i = rows.findIndex(r => r.id === id);
  if (i >= 0) rows[i] = {...rows[i],...changes}; else rows.push({id,...changes});
  _dbSet('profiles', rows);
}

